import akka.actor.Actor
import akka.actor.ActorSystem
import akka.actor.Props

case class Deposit(amount: BigDecimal)
case class Withdraw(amount: BigDecimal)

class AccountManagerActor extends Actor {
  
  var balance: BigDecimal = BigDecimal(0)

  def receive = {
    case Deposit(amount) => 
      if (amount > 0) {
        balance += amount
      }
    case Withdraw(amount) => 
      if (amount > 0 && balance >= amount) {
        balance -= amount
      } else {
        sender() ! "Insufficient balance"
      }
  }
}

object Main{
  def main(args: Array[String]): Unit = {
    val system = ActorSystem("AccountManagerSystem")
    val accountManager = system.actorOf(Props[AccountManagerActor], "accountManager")
  }
}